async (params, browser) => {
  // Open notebook page
  await browser.open(`${params.notebook_url}`)

  // Wait for notebook page
  await browser.waitForSelector('h1, [role=\'main\']', 15000)

  // Let notebook and iframe render
  await browser.wait(4000)

  // Scroll to load more content
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Extract notebook data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim() || document.title.split('|')[0]?.trim() || ''; const authorEl = document.querySelector('a[href*="/code/"]')?.closest('div')?.querySelector('a[href^="/"]') || document.querySelector('a[href*="/users/"]'); const author = authorEl?.textContent?.trim() || ''; const codeCells = []; const outputCells = []; document.querySelectorAll('pre code, pre, .CodeMirror-code, [class*="code"] pre').forEach(el => { const text = el.textContent.trim(); if (text.length > 5 && text.length < 2000) codeCells.push(text.substring(0, 500)); }); document.querySelectorAll('[class*="output"] pre, [class*="Output"], [class*="result"]').forEach(el => { const text = el.textContent.trim(); if (text.length > 5) outputCells.push(text.substring(0, 300)); }); const datasets = []; document.querySelectorAll('a[href*="/datasets/"]').forEach(a => { const href = a.getAttribute('href'); if (href && href.match(/\/datasets\/[^/]+\/[^/]+/)) { datasets.push({ name: a.textContent.trim(), url: 'https://www.kaggle.com' + href }); } }); const allText = document.body.innerText; const votes = allText.match(/(\d+)\s*votes?/i)?.[1] || ''; const comments = allText.match(/(\d+)\s*comments?/i)?.[1] || ''; return { title, author, votes, comments, code_cells: codeCells.slice(0, 10), outputs: outputCells.slice(0, 5), linked_datasets: datasets.slice(0, 5), url: window.location.href };`)

  return page_data
}
